import { Component, OnInit, OnDestroy, Output, EventEmitter } from '@angular/core';
import { Subject, Subscription } from 'rxjs';
import { debounceTime, distinctUntilChanged, switchMap, filter } from 'rxjs/operators';
import { BookingFormService } from '../../services/booking-form.service';
import { NetsuiteService, MobileCheckResult } from '../../services/netsuite.service';
import { Section1 } from '../../models/booking-form.model';

@Component({
  selector: 'app-section1',
  templateUrl: './section1.component.html'
})
export class Section1Component implements OnInit, OnDestroy {

  @Output() applicantType = new EventEmitter();


  form!: Section1;
  showErrors:boolean = false;
  expandedApplicants = [false, false, false, false];

  titles         = ['Mr.','Mrs.','Ms.','Dr.','Prof.'];
  configurations = ['1 BHK','2 BHK','3 BHK','4 BHK','5 BHK','Penthouse','Studio','Duplex'];
  cpTypes        = ['Open','Covered','Mechanical'];
  sourceOptions  = [
    'Newspaper','Hoardings','Website','Magazine','E-Mailers','SMS',
    'Exhibition','Channel Partner','Passing By','Reference','Existing Customer'
  ];

  // ── Mobile duplicate check state ──────────────────────────────────────
  mobileCheckState: 'idle' | 'checking' | 'duplicate' | 'ok' = 'idle';
  mobileDuplicateMatches: Array<{ customerId: string; customerName: string; mobile: string }> = [];

  private mobile$       = new Subject<string>();
  private mobileSub!:    Subscription;

  constructor(
    public  svc: BookingFormService,
    private ns:  NetsuiteService
  ) {}

  ngOnInit() {

    this.svc.section1$.subscribe(s => this.form = s);

    this.setupMobileCheck();
  }

  ngOnDestroy() {
    this.mobileSub?.unsubscribe();
  }

  // ── Wire up the debounced mobile duplicate check ────────────────────────
  // Fires 700 ms after the user stops typing, only when the number looks
  // like a valid Indian mobile (10 digits, optionally prefixed with +91/0).
  private setupMobileCheck(): void {
    this.mobileSub = this.mobile$.pipe(
      debounceTime(700),
      distinctUntilChanged(),
      filter(v => this.looksLikeMobile(v)),
      switchMap(mobile => {
        this.mobileCheckState = 'checking';
        return this.ns.checkMobileDuplicate(mobile);
      })
    ).subscribe({
      next: (result: MobileCheckResult) => {
        if (result.exists) {
          this.mobileCheckState       = 'duplicate';
          this.mobileDuplicateMatches = result.matches || (result.customerId ? [{
            customerId:   result.customerId!,
            customerName: result.customerName || 'Existing Customer',
            mobile:       this.form.mobile
          }] : []);
        } else {
          this.mobileCheckState       = 'ok';
          this.mobileDuplicateMatches = [];
        }
      },
      error: () => {
        // Silent fail — never block the user on a check error
        this.mobileCheckState = 'idle';
      }
    });
  }

  /** Loose validation — 7-15 digits after stripping spaces/+/- */
  private looksLikeMobile(v: string): boolean {
    const digits = (v || '').replace(/[\s\+\-\(\)]/g, '');
    return digits.length >= 7 && digits.length <= 15 && /^\d+$/.test(digits);
  }

  // ── Called on every keystroke on the mobile field ──────────────────────
  onMobileInput(value: string): void {
    this.patch('mobile', value);
    // Reset state immediately on new input so stale "ok"/"duplicate" clears
    this.mobileCheckState       = value.length >= 7 ? 'checking' : 'idle';
    this.mobileDuplicateMatches = [];
    this.mobile$.next(value);
  }

  // ── Existing patch helpers ─────────────────────────────────────────────
  patch(field: string, value: any)        {
    this.applicantType.emit(value);
     this.svc.updateSection1({ [field]: value } as any);
     }
  patchFlat(f: string, v: any)            { this.svc.updateSection1({ flat:          { ...this.form.flat,          [f]: v } }); }
  patchPayment(f: string, v: any)         { this.svc.updateSection1({ payment:       { ...this.form.payment,       [f]: v } }); }
  patchFunding(f: string, v: any)         { this.svc.updateSection1({ funding:       { ...this.form.funding,       [f]: v } }); }
  patchCP(f: string, v: any)              { this.svc.updateSection1({ channelPartner:{ ...this.form.channelPartner,[f]: v } }); }
  patchApplicant(i: number, f: string, v: any) { this.svc.updateApplicant(i, { [f]: v } as any); }

  toggleSource(o: string) {
    const s = [...this.form.source];
    const i = s.indexOf(o); i >= 0 ? s.splice(i,1) : s.push(o);
    this.patch('source', s);
  }
  isSourceOn(o: string) { return this.form.source.includes(o); }
  toggleApplicant(i: number) { this.expandedApplicants[i] = !this.expandedApplicants[i]; }
  toggleTnc() { this.patch('tncAccepted', !this.form.tncAccepted); }

  onPhotoSelected(idx: number, url: string) {
    this.svc.updateSection1({ photos: { ...this.form.photos, [`applicant${idx+1}`]: url } });
  }
  onPhotoCleared(idx: number) {
    const p = { ...this.form.photos }; delete p[`applicant${idx+1}`];
    this.svc.updateSection1({ photos: p });
  }
  onSigned(key: string, url: string) {
    this.svc.updateSection1({ signatures: { ...this.form.signatures, [key]: url } });
  }
  onSignatureCleared(key: string) {
    const s = { ...this.form.signatures }; delete s[key];
    this.svc.updateSection1({ signatures: s });
  }


  // returns the first missing field id or null if valid
getFirstInvalidCPField(): string | null {

       this.showErrors = true;

  // if (!this.form.channelPartner.applicable) {
  //   return true; // not required if No
  // }
  const cp = this.form.channelPartner;
  const ad = this.form.applicants[0];
  const res_addrs = this.form.residenceAddress;
    console.log('address res_addrs: ', res_addrs);
  console.log('ad ad: ', ad)

  if (!cp.applicable) return null;

  if (!cp.name) return 'cp-name';
  if (!cp.mobile) return 'cp-mobile';
  if (!cp.email) return 'cp-email';
  if (!cp.rera) return 'cp-rera';
  if (!cp.gst) return 'cp-gst';
  if (!cp.brokerage) return 'cp-brokerage';



  return null;
}

//   isChannelPartnerValid(): boolean {

//      this.showErrors = true;

//      console.log('check errors: ', this.showErrors);
//   if (!this.form.channelPartner.applicable) {
//     return true; // not required if No
//   }

//   const cp = this.form.channelPartner;

//   return !!(
//     cp.name &&
//     cp.mobile &&
//     cp.email &&
//     cp.rera &&
//     cp.gst &&
//     cp.brokerage
//   );
// }

  /** Expose to template for submit guard */
  get isMobileDuplicate(): boolean { return this.mobileCheckState === 'duplicate'; }
}
<div *ngIf="form">

  <!-- ══ PART A — FLAT DETAILS ══ -->
  <div class="part-head"><span class="part-num">A</span><span class="part-title">Details of Flat Purchased</span></div>
  <div class="fb">
    <div class="g3 mb">
      <div class="f"><label>Project Name</label><input type="text" [value]="form.flat.projectName" (input)="patchFlat('projectName',$any($event.target).value)" placeholder="25 South"/></div>
      <div class="f"><label>Wing / Tower</label><input type="text" [value]="form.flat.wing" (input)="patchFlat('wing',$any($event.target).value)"/></div>
      <div class="f"><label>Flat No.</label><input type="text" [value]="form.flat.flatNo" (input)="patchFlat('flatNo',$any($event.target).value)"/></div>
      <div class="f"><label>Floor</label><input type="text" [value]="form.flat.floor" (input)="patchFlat('floor',$any($event.target).value)"/></div>
      <div class="f">
        <label>Configuration</label>
        <select [value]="form.flat.configuration" (change)="patchFlat('configuration',$any($event.target).value)">
          <option value="">Select</option>
          <option *ngFor="let c of configurations" [value]="c">{{c}}</option>
        </select>
      </div>
      <div class="f"><label>BHK Type</label><input type="text" [value]="form.flat.bhkType" (input)="patchFlat('bhkType',$any($event.target).value)"/></div>
      <div class="f"><label>RERA Carpet Area (Sq.Mt.)</label><input type="text" [value]="form.flat.reraCarpet" (input)="patchFlat('reraCarpet',$any($event.target).value)"/></div>
      <div class="f"><label>Along With Area (Sq.Mt.)</label><input type="text" [value]="form.flat.alongWithArea" (input)="patchFlat('alongWithArea',$any($event.target).value)"/></div>
      <div class="f"><label>Car Parking No.</label><input type="text" [value]="form.flat.cpNo" (input)="patchFlat('cpNo',$any($event.target).value)"/></div>
      <div class="f"><label>Car Parking Level</label><input type="text" [value]="form.flat.cpLevel" (input)="patchFlat('cpLevel',$any($event.target).value)"/></div>
      <div class="f">
        <label>Car Parking Type</label>
        <select [value]="form.flat.cpType" (change)="patchFlat('cpType',$any($event.target).value)">
          <option value="">Select</option>
          <option *ngFor="let t of cpTypes" [value]="t">{{t}}</option>
        </select>
      </div>
      <div class="f">
        <label>End Use</label>
        <div class="rg">
          <div class="rp" [class.on]="form.flat.endUse==='Self Use'"  (click)="patchFlat('endUse','Self Use')">Self Use</div>
          <div class="rp" [class.on]="form.flat.endUse==='Investment'" (click)="patchFlat('endUse','Investment')">Investment</div>
        </div>
      </div>
      <div class="f span2"><label>Sale Value (Figures)</label><input type="text" [value]="form.flat.saleValue" (input)="patchFlat('saleValue',$any($event.target).value)" placeholder="₹"/></div>
      <div class="f span3"><label>Sale Value (Words)</label><input type="text" [value]="form.flat.saleValueWords" (input)="patchFlat('saleValueWords',$any($event.target).value)"/></div>
    </div>
  </div>

  <!-- ══ PART B — APPLICANT DETAILS ══ -->
  <div class="part-head"><span class="part-num">B</span><span class="part-title">Applicant Details</span></div>
  <div class="fb">
    <div *ngFor="let app of form.applicants; let i = index" class="applicant-row mb">
      <div class="applicant-header" (click)="toggleApplicant(i)">
        <span class="app-index">Applicant {{i+1}}</span>
        <div class="g4" style="flex:1">
          <div class="f">
            <select [value]="app.title" (change)="patchApplicant(i,'title',$any($event.target).value)">
              <option value="">Title</option>
              <option *ngFor="let t of titles" [value]="t">{{t}}</option>
            </select>
          </div>
          <div class="f"><input type="text" [value]="app.firstName"  (input)="patchApplicant(i,'firstName',$any($event.target).value)"  placeholder="First Name"/></div>
          <div class="f"><input type="text" [value]="app.middleName" (input)="patchApplicant(i,'middleName',$any($event.target).value)" placeholder="Middle Name"/></div>
          <div class="f"><input type="text" [value]="app.lastName"   (input)="patchApplicant(i,'lastName',$any($event.target).value)"   placeholder="Last Name"/></div>
        </div>
        <button class="expand-btn" type="button">{{ expandedApplicants[i] ? '▲ Hide' : '▼ Details' }}</button>
      </div>
      <div class="applicant-details" *ngIf="expandedApplicants[i]">
        <div class="g3">
          <div class="f" *ngIf="i>0"><label>Relation to Applicant 1</label><input type="text" [value]="app.relation" (input)="patchApplicant(i,'relation',$any($event.target).value)"/></div>
          <div class="f"><label>Date of Birth</label><input type="date" [value]="app.dob" (change)="patchApplicant(i,'dob',$any($event.target).value)"/></div>
          <div class="f"><label>Anniversary</label><input type="date" [value]="app.anniversary" (change)="patchApplicant(i,'anniversary',$any($event.target).value)"/></div>
          <div class="f"><label>PAN</label><input type="text" [value]="app.pan" (input)="patchApplicant(i,'pan',$any($event.target).value)" style="text-transform:uppercase" maxlength="10"/></div>
          <div class="f"><label>Occupation</label><input type="text" [value]="app.occupation" (input)="patchApplicant(i,'occupation',$any($event.target).value)"/></div>
        </div>
      </div>
    </div>
    <hr/>
    <div class="g2 mb">
      <div class="f"><label>Residence Address <span class="req">*</span></label><textarea [value]="form.residenceAddress" (input)="patch('residenceAddress',$any($event.target).value)"></textarea></div>
      <div class="f"><label>Correspondence Address</label><textarea [value]="form.correspondenceAddress" (input)="patch('correspondenceAddress',$any($event.target).value)"></textarea></div>
    </div>
    <div class="f mb">
      <label>Residence Ownership</label>
      <div class="rg">
        <div class="rp" *ngFor="let o of ['Owned','Rented','Parental','Joint Family']" [class.on]="form.ownership===o" (click)="patch('ownership',o)">{{o}}</div>
      </div>
    </div>
    <div class="f mb">
      <label>Any Other Property?</label>
      <div class="rg">
        <div class="rp" [class.on]="form.otherProp==='Yes'" (click)="patch('otherProp','Yes')">Yes</div>
        <div class="rp" [class.on]="form.otherProp==='No'"  (click)="patch('otherProp','No')">No</div>
      </div>
    </div>
    <div class="f mb" *ngIf="form.otherProp==='Yes'">
      <label>City / Location</label>
      <input type="text" [value]="form.otherPropCity" (input)="patch('otherPropCity',$any($event.target).value)"/>
    </div>
    <div class="g3 mb">
      <div class="f">
        <label>Profession</label>
        <div class="rg">
          <div class="rp" *ngFor="let p of ['Business','Service','Professional']" [class.on]="form.profession===p" (click)="patch('profession',p)">{{p}}</div>
        </div>
      </div>
      <div class="f"><label>Organization</label><input type="text" [value]="form.organization" (input)="patch('organization',$any($event.target).value)"/></div>
      <div class="f"><label>Designation</label><input type="text" [value]="form.designation"   (input)="patch('designation',$any($event.target).value)"/></div>
    </div>
    <div class="g3 mb">
      <!-- ── MOBILE — duplicate check on input ── -->
      <div class="f mobile-field-wrap">
        <label>Mobile <span class="req">*</span></label>
        <div class="mobile-input-row">
          <input
            type="tel"
            [value]="form.mobile"
            (input)="onMobileInput($any($event.target).value)"
            [class.input-checking]="mobileCheckState === 'checking'"
            [class.input-ok]="mobileCheckState === 'ok'"
            [class.input-error]="mobileCheckState === 'duplicate'"
            placeholder="10-digit mobile number"
            maxlength="15"
          />
          <!-- Inline status icon -->
          <span class="mobile-status-icon" *ngIf="mobileCheckState !== 'idle'">
            <span *ngIf="mobileCheckState === 'checking'" class="spin-icon" title="Checking…">⟳</span>
            <span *ngIf="mobileCheckState === 'ok'"       class="ok-icon"   title="Available">✓</span>
            <span *ngIf="mobileCheckState === 'duplicate'" class="err-icon"  title="Duplicate">✕</span>
          </span>
        </div>

        <!-- Checking hint -->
        <div class="mobile-hint checking" *ngIf="mobileCheckState === 'checking'">
          Checking NetSuite…
        </div>

        <!-- OK hint -->
        <div class="mobile-hint ok" *ngIf="mobileCheckState === 'ok'">
          ✓ No existing customer with this number
        </div>

        <!-- Duplicate warning — shows all matching customers -->
        <div class="mobile-duplicate-warning" *ngIf="mobileCheckState === 'duplicate'">
          <div class="dup-header">
            ⚠ This mobile number already exists in NetSuite
          </div>
          <div class="dup-match" *ngFor="let m of mobileDuplicateMatches">
            <span class="dup-name">{{ m.customerName }}</span>
            <span class="dup-id">(ID: {{ m.customerId }})</span>
          </div>
          <div class="dup-note">
            You can still proceed — this will create a new booking linked to a new customer record.
          </div>
        </div>
      </div>

      <div class="f"><label>Residence Phone</label><input type="tel" [value]="form.residencePhone"  (input)="patch('residencePhone',$any($event.target).value)"/></div>
      <div class="f"><label>Email <span class="req">*</span></label><input type="email" [value]="form.email" (input)="patch('email',$any($event.target).value)"/></div>
    </div>
    <div class="f mb">
      <label>Residential Status</label>
      <div class="rg">
        <div class="rp" *ngFor="let s of ['Resident Indian','NRI','PIO','OCI']" [class.on]="form.residentialStatus===s" (click)="patch('residentialStatus',s)">{{s}}</div>
      </div>
    </div>
    <div class="g3 mb" *ngIf="['NRI','PIO','OCI'].includes(form.residentialStatus)">
      <div class="f"><label>Country</label><input type="text" [value]="form.nriCountry"           (input)="patch('nriCountry',$any($event.target).value)"/></div>
      <div class="f"><label>Local Contact No.</label><input type="tel" [value]="form.localContactNo" (input)="patch('localContactNo',$any($event.target).value)"/></div>
      <div class="f"><label>Local Contact Person</label><input type="text" [value]="form.localContactPerson" (input)="patch('localContactPerson',$any($event.target).value)"/></div>
    </div>
  </div>

  <!-- ══ PART D — FUNDING ══ -->
  <div class="part-head"><span class="part-num">D</span><span class="part-title">Source of Funding</span></div>
  <div class="fb">
    <div class="f mb">
      <label>Home Loan Opted</label>
      <div class="rg">
        <div class="rp" *ngFor="let l of ['Yes','No','Not Yet Decided']" [class.on]="form.funding.loanOpted===l" (click)="patchFunding('loanOpted',l)">{{l}}</div>
      </div>
    </div>
    <div class="g3" *ngIf="form.funding.loanOpted==='Yes'">
      <div class="f"><label>Bank / FI Name</label><input type="text" [value]="form.funding.bankName"   (input)="patchFunding('bankName',$any($event.target).value)"/></div>
      <div class="f"><label>Own Contribution %</label><input type="text" [value]="form.funding.ownContrib" (input)="patchFunding('ownContrib',$any($event.target).value)"/></div>
      <div class="f"><label>Home Loan %</label><input type="text" [value]="form.funding.homeLoan"      (input)="patchFunding('homeLoan',$any($event.target).value)"/></div>
    </div>
  </div>

  <!-- ══ PART E — SOURCE ══ -->
  <div class="part-head"><span class="part-num">E</span><span class="part-title">Source of Booking</span></div>
  <div class="fb">
    <div class="cg">
      <div class="cp" *ngFor="let s of sourceOptions" [class.on]="isSourceOn(s)" (click)="toggleSource(s)">{{s}}</div>
    </div>
    <div class="f" style="margin-top:12px"><label>Others</label><input type="text" [value]="form.sourceOther" (input)="patch('sourceOther',$any($event.target).value)"/></div>
  </div>

  <!-- ══ PART F — CHANNEL PARTNER ══ -->
  <div class="part-head"><span class="part-num">F</span><span class="part-title">Channel Partner Details</span></div>
  <div class="fb">
    <div class="f mb">
      <label>Channel Partner Applicable?</label>
      <div class="rg">
        <div class="rp" [class.on]="form.channelPartner.applicable"  (click)="patchCP('applicable',true)">Yes</div>
        <div class="rp" [class.on]="!form.channelPartner.applicable" (click)="patchCP('applicable',false)">No</div>
      </div>
    </div>
    <div class="g3" *ngIf="form.channelPartner.applicable">
      <div class="f"><label>Name</label><input  id="cp-name"  type="text" [class.error]="showErrors && form.channelPartner.applicable && !form.channelPartner.name"  [value]="form.channelPartner.name"     (input)="patchCP('name',$any($event.target).value)"/></div>
      <div class="f"><label>Mobile</label><input id="cp-mobile" type="tel" [class.error]="showErrors && form.channelPartner.applicable && !form.channelPartner.mobile" [value]="form.channelPartner.mobile"   (input)="patchCP('mobile',$any($event.target).value)"/></div>
      <div class="f"><label>Email</label><input id="cp-email" type="email" [class.error]="showErrors && form.channelPartner.applicable && !form.channelPartner.email" [value]="form.channelPartner.email"    (input)="patchCP('email',$any($event.target).value)"/></div>
      <div class="f"><label>RERA No.</label><input id="cp-rera"  type="text"  [class.error]="showErrors && form.channelPartner.applicable && !form.channelPartner.rera"[value]="form.channelPartner.rera"   (input)="patchCP('rera',$any($event.target).value)"/></div>
      <div class="f"><label>GST No.</label><input id="cp-gst" type="text"  [class.error]="showErrors && form.channelPartner.applicable && !form.channelPartner.gst" [value]="form.channelPartner.gst"     (input)="patchCP('gst',$any($event.target).value)"/></div>
      <div class="f"><label>Brokerage %</label><input id="cp-brokerage" type="text" [class.error]="showErrors && form.channelPartner.applicable && !form.channelPartner.brokerage" [value]="form.channelPartner.brokerage" (input)="patchCP('brokerage',$any($event.target).value)"/></div>
    </div>
  </div>

  <!-- ══ PART H — BOOKING PAYMENT ══ -->
  <div class="part-head"><span class="part-num">H</span><span class="part-title">Booking Payment Details</span></div>
  <div class="fb">
    <div class="g3">
      <div class="f"><label>Cheque / UTR No.</label><input type="text" [value]="form.payment.chequeNo"    (input)="patchPayment('chequeNo',$any($event.target).value)"/></div>
      <div class="f"><label>Date</label><input type="date" [value]="form.payment.dated"                   (change)="patchPayment('dated',$any($event.target).value)"/></div>
      <div class="f"><label>Amount (Figures)</label><input type="text" [value]="form.payment.amount"      (input)="patchPayment('amount',$any($event.target).value)" placeholder="₹"/></div>
      <div class="f span3"><label>Amount (Words)</label><input type="text" [value]="form.payment.amountWords" (input)="patchPayment('amountWords',$any($event.target).value)"/></div>
      <div class="f span3"><label>Drawn On (Bank)</label><input type="text" [value]="form.payment.drawnOn"    (input)="patchPayment('drawnOn',$any($event.target).value)"/></div>
      <div class="f span3"><label>Cost Sheet Ref.</label><input type="text" [value]="form.payment.costSheetRef" (input)="patchPayment('costSheetRef',$any($event.target).value)"/></div>
    </div>
  </div>

  <!-- ══ PHOTOGRAPHS & SIGNATURES ══ -->
  <div class="part-head"><span class="part-num">📷</span><span class="part-title">Photograph &amp; Signature</span></div>
  <div class="fb">
    <p class="sub-note" style="margin-bottom:18px">
      Upload a passport-size photograph for each applicant. Sign in the box below using finger, stylus, or mouse.
    </p>
    <div class="photo-sig-grid">
      <div class="photo-sig-col" *ngFor="let app of form.applicants; let i = index">
        <app-photo-upload
          [label]="'Applicant ' + (i+1)"
          [sublabel]="i===0 ? '(Primary)' : ''"
          (photoSelected)="onPhotoSelected(i,$event)"
          (photoCleared)="onPhotoCleared(i)">
        </app-photo-upload>
        <app-signature-pad
          [label]="'Signature ' + (i+1)"
          [mandatory]="i===0"
          (signed)="onSigned('applicant'+(i+1),$event)"
          (cleared)="onSignatureCleared('applicant'+(i+1))">
        </app-signature-pad>
      </div>
    </div>
    <div style="margin-top:24px; max-width:280px">
      <p class="sub-note" style="margin-bottom:10px">Channel Partner / Witness Signature</p>
      <app-signature-pad
        label="Channel Partner / Witness"
        [mandatory]="false"
        (signed)="onSigned('channelPartner',$event)"
        (cleared)="onSignatureCleared('channelPartner')">
      </app-signature-pad>
    </div>
  </div>

  <!-- ══ T&C ══ -->
  <div class="part-head"><span class="part-num">T&amp;C</span><span class="part-title">Terms &amp; Conditions</span></div>
  <div class="fb">
    <div class="note">Please read all Terms &amp; Conditions before accepting. Ticking below confirms you have read, understood and agree to all 46 clauses.</div>
    <div class="tnc-row" (click)="toggleTnc()">
      <div class="tnc-box" [class.checked]="form.tncAccepted"><span *ngIf="form.tncAccepted">✓</span></div>
      <div class="tnc-text">I / We have read, understood and agree to be bound by all Terms &amp; Conditions forming part of this Booking Form.</div>
    </div>
  </div>

</div>
